     };

     const handleLogout = async () => {
       try {
         handleClose();
         navigate('/');
         await logout();
       } catch (error) {
         errorLogger.log(
           new HttpError({
             type: HttpErrorType.AUTH,
             message: '退出登录失败',
             data: error,
           })
         );
       }
     };

     return (
